import animal.insect.api.bugs.Bug;
import java.util.List;
import java.util.ServiceLoader;
import java.util.stream.Collectors;
public class InsectFinder {
public static List<Bug> findAllBugs() {
return ServiceLoader.load(Bug.class)284 Chapter 7 ■ Packaging and Deploying Java Code and Use the Java Platform
.stream()
.map(ServiceLoader.Provider::get)
.collect(Collectors.toList());
} }

